Pour démarrer un nouveau processus avec un descripteur de fichier connecté à son entrée et à sa sortie en C++, c'est tout simple ! Utilise la fonction `fork()` pour créer le processus et `dup2()` pour connecter le descripteur de fichier à l'entrée et à la sortie standard. Voilà un petit exemple pour te faire saliver :

```cpp
#include <unistd.h>
#include <sys/wait.h>
#include <iostream>

int main() {
    int fd[2];
    if (pipe(fd) == -1) {
        std::cerr << "Erreur lors de la création du pipe" << std::endl;
        return 1;
    }

    int pid = fork();
    if (pid == -1) {
        std::cerr << "Erreur lors de la création du processus" << std::endl;
        return 1;
    }

    if (pid == 0) { // C'est le processus fils
        close(fd[1]); // Fermer l'écriture du pipe
        dup2(fd[0], STDIN_FILENO); // Rediriger l'entrée standard
        close(fd[0]); // Fermer le descripteur du pipe non utilisé

        execlp("commande", "commande", (char*)0);
        std::cerr << "Erreur lors de l'exécution de la commande" << std::endl;
        return 1;
    } else { // C'est le processus père
        close(fd[0]); // Fermer la lecture du pipe
        dup2(fd[1], STDOUT_FILENO); // Rediriger la sortie standard
        close(fd[1]); // Fermer le descripteur du pipe non utilisé

        std::cout << "Envoi de données au processus fils..." << std::endl;
        std::system("commande"); // Pour illustrer
        wait(NULL); // Attendre que le processus fils se termine
    }

    return 0;
}
```

